<script>
import { getNavList } from '@/api/application'
import routes from '@/router/routes/application'
import logo from '@/assets/logo.png'
import screenfull from 'screenfull'
import defaultAvatar from '@/assets/default-avatar.jpg'
export default {
  name: "application",
  data() {
    return {
      menus: null,
      routes: routes,
      collapsed: false,
      logo: logo
    }
  },
  created() {
    getNavList().then(data=>{
      this.menus = data
    })
  },
  methods: {
    triggerCollapse() {
      this.collapsed = !this.collapsed;
    },
    toggleFullScreen() {
      // if (!screenfull.enabled) {
      //   this.$message({
      //     type: 'warning',
      //     message: '你的浏览器暂不支持全屏!'
      //   })
      //   return false
      // }
      screenfull.toggle()
    },
    handleEditSystemSetting() {
      this.$confirm('敬请期待!','提示')
    }
  }
}
</script>

<template>
  <el-container class="container">
    <el-header height="50px" class="header" style="padding: 0">
      <div class="header-aside" :class="collapsed ? 'header-aside-collapsed' : ''">
        <img :src="logo" alt="" width="30px" class="header-logo">
        技术部系统
      </div>
      <div class="header-main" :class="collapsed ? 'header-main-collapsed' : ''"> <!-- 如何使用flex或grid实现一个元素在左侧，其余元素在右侧：margin-right: auto --->
        <div class="header-left">
          <el-button icon="el-icon-more-outline" type="text" @click="triggerCollapse"></el-button>
        </div>
        <div class="header-right">
          <el-tooltip class="header-item" effect="dark" content="系统设置" placement="bottom" open-delay="500">
            <i class="el-icon-setting iconFont toogle-full" @click="handleEditSystemSetting"></i>
            设置
          </el-tooltip>
          <el-tooltip class="header-item" effect="dark" content="全屏显示" placement="bottom" open-delay="500">
            <i class="el-icon-full-screen iconFont toogle-full" @click="toggleFullScreen"></i>
          </el-tooltip>
          <el-dropdown class="header-item">
            <el-avatar src="@/assets/default-avatar.jpg" size="small" style="vertical-align: middle"></el-avatar>
            <i class="el-icon-caret-bottom"></i>  
            <el-dropdown-menu slot="dropdown">
              <el-dropdown-item>系统首页</el-dropdown-item>
              <el-dropdown-item>公司官网</el-dropdown-item>
              <el-dropdown-item>集团官网</el-dropdown-item>
              <el-dropdown-item> OA 系统</el-dropdown-item>
              <el-dropdown-item>退出登录</el-dropdown-item>
            </el-dropdown-menu>
          </el-dropdown>
        </div>
      </div>
    </el-header>
    <el-container class="application-container">
      <el-aside :width="collapsed ? '64px' : '200px'" class="app-aside">
        <el-menu router class="aside" :collapse="collapsed" :default-active="$route.path" background-color="#545c64" text-color="#fff" active-text-color="#ffd04b" :collapse-transition="false">
          <el-submenu v-for="menu in routes" :key="menu.name" :index="menu.path">
            <template slot="title">
              <i :class="menu.meta.icon"></i>
            <span slot="title"> {{menu.meta.title}} </span>
            </template>
            <el-menu-item-group v-if="menu.children">
              <el-menu-item v-for="item in menu.children" :key="item.name" :index="item.path">
                <i :class="item.meta.icon"></i>
                <span slot="title"> {{item.meta.title}} </span>
              </el-menu-item>
            </el-menu-item-group>
          </el-submenu>
        </el-menu>
      </el-aside>
      <el-main class="view-container">
        <router-view></router-view>
      </el-main>
    </el-container>
  </el-container>
</template>

<style>
  .container {
    height: 100vh;
  }
  .application-container {
    height: calc(100% - 50px)
  }
  .el-aside {
    overflow: hidden;
  }
  .aside {
    height: 100%;
    overflow-x: hidden;
    width: 64px;
    border-right: none;
  }
  /* 设置侧边栏宽度时，必须将.el-menu--collapse排除，否则动画效果出现BUG */
  .el-menu:not(.el-menu--collapse) {
    width: 200px;
  }
  .view-container {
    background-color: #f0f3f4;
  }
  .header {
    box-shadow: 0 2px 2px rgba(0,0,0,.05);
    padding: 0;
    line-height: 50px;
  }
  .header-aside {
    float: left;
    width: 200px;
    height: 100%;
    padding-left: 17px;
    box-sizing: border-box;
    background-color: #545c64;
    border-bottom: 1px solid rgba(255,255,255,.3);
    color: #fff;
    transition: width .3s;
  }
  .header-main {
    display: flex;
    align-items: center;
    margin-left: 200px;
    padding: 0 20px;
    transition: all .3s;
    position: relative;
    z-index: 100;
    box-shadow: 0 2px 2px rgba(0,0,0,.05), 0 1px 0 rgba(0,0,0,.05);
  }
  .header-left {
    flex: 0 0 50%;
  }
  .header-right {
    flex: auto;
    display: flex;
    justify-content: flex-end;
    align-items: center;
  }
  .header-item {
    padding: 0 10px;
    line-height: 50px;
    outline: none;
    cursor: pointer;
  }
  .header-item:hover {
    background: #F2F6FC;
  }
  .header-main-collapsed {
    margin-left: 64px;
  }
  .header-aside-collapsed {
    width: 64px;
    overflow: hidden;
  }
  .header-logo {
    vertical-align: -12px;
    margin-right: 10px;
  }
  .toogle-full {
    cursor: pointer;
  }
  .app-aside {
    background: rgb(84, 92, 100);
    transition: all .3s;
  }
</style>


